function BlockRenderer({ block }: { block: any }) {
  switch (block._block) {
    case 'hero':
      return (
        <section>
          <h1>{block.tagline}</h1>
          <p>{block.description}</p>
        </section>
      );
    case 'features':
      return (
        <section>
          <h2>{block.title}</h2>
          <div className="grid grid-cols-3 gap-4">
            {block.items?.map((item: any, i: number) => (
              <div key={i}>
                <h3>{item.title}</h3>
                <p>{item.description}</p>
              </div>
            ))}
          </div>
        </section>
      );
    default:
      return null;
  }
}
